var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"허억...... 허억......","JPN":"はあ……はあ……","ENG":"Huff... Huff...","TWN":"咳……咳……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"체르노프 박사. 무슨 일인가?","JPN":"チェルノフ博士。どうした？","ENG":"Doctor Chernov. What is wrong?","TWN":"切爾諾夫博士。怎麼了？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"출혈이 심하다. 즉시 병원으로 이동할 것을 권고한다.","JPN":"出血がひどい。直ちに病院への移動を勧める。","ENG":"You are bleeding severely. I recommend you get to a hospital immediately.","TWN":"你出血很嚴重。建議立即去醫院。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그랬으면 좋겠지만...... 지금 병원에 갈 상황이 아니라서 말이야.","JPN":"そうしたいのはやまやまだが……今は無理だ。","ENG":"I would, but... I'm afraid that will have to wait right now.","TWN":"我也想啊……但現在這情況想去也去不了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"격납고 밖에서 심상치 않은 소음이 탐지됐다.","JPN":"格納庫の外から、ただならない騒音が感知された。","ENG":"Suspicious noise has been detected outside the hangar.","TWN":"探測到機庫外有奇怪的噪音。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"침식 재난이 발발한 것인가?","JPN":"侵食災害が発生したのか？","ENG":"Has a Corruption Disaster broken out?","TWN":"是發生侵蝕災難了嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"습격이다......","JPN":"襲撃だ……","ENG":"We're under attack...","TWN":"是突襲……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"빌어먹을...... 요새 이상하게 경비 부대가 줄어들었다고 생각했는데......","JPN":"ちくしょう……最近、妙に警備部隊が減ったと思ったら……","ENG":"Damn it... I knew there was something fishy about the reduction in security lately...","TWN":"該死的……我還在想最近怎麼警備隊都消失了……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"체르노프 박사, 맥박이 떨어지고 있다.","JPN":"チェルノフ博士、脈が低下している。","ENG":"Dr. Chernov, your pulse grows thin.","TWN":"切爾諾夫博士，你的脈搏在下降。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"말을 멈추고 안정을 취하도록. 위험 상태에 도달했다.","JPN":"黙って安静にしていろ。危険状態に達した。","ENG":"Stop talking and try to relax. You are in critical condition.","TWN":"不要說話，請保持安靜，你已經到達危險狀態。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"나도 그러고 싶지만...... 먼저 처리해야 할 일이 있어......","JPN":"私もそうしたいが……先に処理することがある……","ENG":"I wish I could... But there's something I have to take care of first.","TWN":"我也想啊，但是……有件事我得先處理一下……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"나의 고정 장치가 해제됐다. 전 시스템 컨트롤 가능.","JPN":"吾輩の固定装置が解除された。全システム、コントロール可能。","ENG":"My locks have been disabled. All systems now operational.","TWN":"我的鎖定裝置已解除，可以控制系統。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"박사가 한 일인가?","JPN":"博士が解除したのか？","ENG":"Did you do this?","TWN":"這是博士做的嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그래...... 쿨럭! 쿨럭!","JPN":"そうだ……ゲホ！　ゲホ！","ENG":"Yes... *Cough!* *Cough!*","TWN":"對……咳咳！咳咳！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"잘 들어...... 놈들이 노리는 건 바로 너야.","JPN":"よく聞け……君は今、狙われてる。","ENG":"Listen closely... You're the one they're after.","TWN":"好好聽著……他們的目標是你。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"저 놈들은 널 그저 전쟁병기로밖에 생각하지 않는 자들이니까.","JPN":"あいつらは君のことを、戦争兵器だとしか思ってない。","ENG":"They think of you as nothing more than a war machine.","TWN":"那些傢伙只把你當作戰爭武器。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그런 녀석들에게 널 넘겨줄 순...... 없어.","JPN":"そんなやつらに、君を渡すわけにはいか……ない。","ENG":"I can't let you fall into... their hands.","TWN":"想要我把你交出來……想都別想。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};